) -> Result<SP1ProofWithPublicValues, BoxError> {
    let node = timed_async("build_local_node", || async {
        SP1LocalNodeBuilder::from_worker_client_builder(cpu_worker_builder())
            .build()
            .await
    })
    .await?;
