        check_exact_len(bytes, PRIVATE_CONTINUATION_STATE_SIZE)?;
        let current_nbits = CompactTarget::new(u32::from_le_bytes(bytes[0..4].try_into().unwrap()));
        let current_work = ChainWork::from_le_bytes(bytes[4..36].try_into().unwrap());
