pub(crate) fn find_first_diverging_state_index(
    states: &[util::State],
    first_new_height: u32,
    db_path: &str,
    genesis_hash: util::BlockHash,
) -> usize {
    assert!(
        !states.is_empty(),
        "find_first_diverging_state_index requires at least one state"
    );

    let mut lo: usize = 0;
    let mut hi: usize = states.len() - 1;

    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        let height = first_new_height + (mid as u32);
        let db_state = util::state_from_db_at_height(db_path, height, genesis_hash);

        if states[mid].public_claim() == db_state.public_claim() {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }

    lo
}

pub(crate) async fn execute_batch_with_prover<P, K>(
    prover_name: &str,
    prover: &P,
    proving_key: &K,
    batch: &PreparedBatch,
) -> Result<ExecutedBatchArtifacts, BoxError>
where
    config: &ProofGenerationConfig,
    first_new_height: u32,
) -> Result<util::HeaderBatchWitness, BoxError> {
    timed_sync("load_header_witness", || -> Result<_, BoxError> {
        Ok(util::load_header_batch_witness_from_db(
            path_to_str(&config.db_path)?,
            first_new_height as u64,
            config.num_headers as u64,
        ))
    })
}

fn simulate_expected_state(
    config: &ProofGenerationConfig,
    genesis_hash: util::BlockHash,
    current_state: &util::State,
    headers: &[util::NewHeader],
    median_hints: &[util::BlockTimestamp],
    first_new_height: u32,
    end_height: u32,
) -> Result<util::State, BoxError> {
    let expected_state = timed_sync("simulate_expected_state", || -> Result<_, BoxError> {
        Ok(util::compute_final_state_with_hints(
            current_state,
            headers,
            median_hints,
        ))
    })?;

    let db_end_state = timed_sync("load_db_end_state", || -> Result<_, BoxError> {
        Ok(util::state_from_db_at_height(
            path_to_str(&config.db_path)?,
            end_height,
            genesis_hash,
        ))
    })?;

    if expected_state.public_claim() == db_end_state.public_claim() {
        return Ok(expected_state);
    }

    let (bad_index, actual_state) = timed_sync("bisect_divergence", || -> Result<_, BoxError> {
        find_first_diverging_state(
            current_state,
            headers,
            median_hints,
            first_new_height,
            path_to_str(&config.db_path)?,
            genesis_hash,
        )
    })?;

    let bad_height = first_new_height + (bad_index as u32);
    let expected_claim =
        util::state_from_db_at_height(path_to_str(&config.db_path)?, bad_height, genesis_hash)
            .public_claim();
    let actual_claim = actual_state.public_claim();

    Err(format!(
        "host simulation diverges from database\n  first bad header index in batch: {}\n  bad height: {}\n{}",
        bad_index,
        bad_height,
        format_claim_mismatch(&actual_claim, &expected_claim),
    )
    .into())
}

